// Phase 1: Detect cycle
slow = head, fast = head
while fast and fast.next:
  slow = slow.next
  fast = fast.next.next
  if slow == fast: break

// Phase 2: Find cycle start
slow = head
while slow != fast:
  slow = slow.next
  fast = fast.next
return slow  // cycle start

