// Subarray Sum Equals K
prefixSum = 0, count = 0
map = {0: 1}
for num in nums:
  prefixSum += num
  if (prefixSum - k) in map:
    count += map[prefixSum - k]
  map[prefixSum] = map.get(prefixSum, 0) + 1
return count
